#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647L
#define A 1103515245
#define C 12345

inline double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return (double)newValue;
    else
        return (double)(newValue++);
}

inline double randu(__global int *seed, int index) {
    long num = ((long)A * (long)seed[index]) + (long)C;
    seed[index] = (int)(num % M);
    return fabs((double)seed[index] / (double)M);
}

inline double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int findIndex(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

__kernel void likelihood_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *xj,
    __global double *yj,
    __global double *CDF,
    __global int *ind,
    __global int *objxy,
    __global double *likelihood,
    __global uchar *I,
    __global double *u,
    __global double *weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    __global int *seed,
    __global double *partial_sums,
    __local double *buffer
) {
    int x = (int)get_global_id(0);
    if (x >= Nparticles) return;

    (void)CDF;
    (void)u;
    (void)buffer;

    arrayX[x] = xj[x] + 1.0 + 5.0 * randn(seed, x);
    arrayY[x] = yj[x] - 2.0 + 2.0 * randn(seed, x);

    double like = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
        int idx = indX * IszY * Nfr + indY * Nfr + k;
        if (idx < 0) idx = -idx;
        if (idx >= max_size) idx = 0;
        ind[x * countOnes + y] = idx;

        double pixel = (double)I[idx];
        like += ((pixel - 100.0) * (pixel - 100.0) - (pixel - 228.0) * (pixel - 228.0)) / 50.0;
    }

    like = like / (double)countOnes;
    likelihood[x] = like;
    weights[x] = weights[x] * exp(like);
    partial_sums[x] = weights[x];
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = (int)get_global_id(0);
    if (gid != 0) return;

    double sumWeights = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        sumWeights += partial_sums[i];
    }
    partial_sums[0] = sumWeights;
}

__kernel void normalize_weights_kernel(
    __global double *weights,
    int Nparticles,
    __global double *partial_sums,
    __global double *CDF,
    __global double *u,
    __global int *seed
) {
    int gid = (int)get_global_id(0);
    if (gid != 0) return;

    double sumWeights = partial_sums[0];
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = weights[i] + CDF[i - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i / (double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *CDF,
    __global double *u,
    __global double *xj,
    __global double *yj,
    __global double *weights,
    int Nparticles
) {
    int j = (int)get_global_id(0);
    if (j >= Nparticles) return;

    int i = findIndex(CDF, Nparticles, u[j]);
    if (i == -1) i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
    weights[j] = 1.0 / (double)Nparticles;
}

